import{_ as t,o as a,c as o,a2 as i}from"./chunks/framework.C69UpXSI.js";const h=JSON.parse('{"title":"Memoria Persistente","description":"","frontmatter":{},"headers":[],"relativePath":"it/configurazione/memory.md","filePath":"it/configurazione/memory.md"}'),n={name:"it/configurazione/memory.md"};function s(r,e,l,d,c,p){return a(),o("div",null,[...e[0]||(e[0]=[i(`<h1 id="memoria-persistente" tabindex="-1">Memoria Persistente <a class="header-anchor" href="#memoria-persistente" aria-label="Permalink to &quot;Memoria Persistente&quot;">​</a></h1><p>TurboDev ha un sistema di <strong>memoria persistente</strong> integrato che permette all&#39;agente AI di ricordare le tue preferenze, decisioni e fatti del progetto tra una sessione e l&#39;altra. Niente più partenze da zero ogni volta che riapri il terminale — l&#39;agente impara e conserva il contesto che conta.</p><h2 id="come-funziona" tabindex="-1">Come Funziona <a class="header-anchor" href="#come-funziona" aria-label="Permalink to &quot;Come Funziona&quot;">​</a></h2><ol><li>All&#39;avvio, TurboDev carica <code>.turbodev/memory.md</code> (un file Markdown plain, gitignored)</li><li>Il contenuto viene iniettato nel system prompt sotto una sezione <code>## Memory</code></li><li>L&#39;LLM vede i fatti persistenti e li usa come contesto</li><li>Quando l&#39;LLM impara qualcosa di duraturo, chiama automaticamente il tool <code>save_memory</code></li><li>La memoria <strong>sopravvive alla compattazione</strong> perché vive nel system prompt (non nella cronologia della conversazione)</li></ol><p>Puoi anche gestire la memoria manualmente con i comandi <code>/memory</code> o editando direttamente il file.</p><h2 id="formato-markdown" tabindex="-1">Formato Markdown <a class="header-anchor" href="#formato-markdown" aria-label="Permalink to &quot;Formato Markdown&quot;">​</a></h2><p><code>.turbodev/memory.md</code> è un file Markdown plain con una sezione per categoria:</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;"># Project Memory</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## preferences</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> User prefers TypeScript over JavaScript</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Prefers functional style over OOP</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## decisions</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Using OpenRouter as LLM provider</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## architecture</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> React + Ink for TUI, tsup for bundling</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## facts</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Node 22 LTS is installed</span></span></code></pre></div><p>Il file è sempre leggibile e modificabile. Dopo modifiche manuali, esegui <code>/memory reload</code> per aggiornare la sessione.</p><h2 id="categorie" tabindex="-1">Categorie <a class="header-anchor" href="#categorie" aria-label="Permalink to &quot;Categorie&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Categoria</th><th>Descrizione</th><th>Esempi</th></tr></thead><tbody><tr><td><code>preferences</code></td><td>Come l&#39;utente preferisce le cose</td><td>&quot;prefers pnpm over npm&quot;, &quot;likes functional style&quot;</td></tr><tr><td><code>decisions</code></td><td>Scelte a livello progetto che persistono</td><td>&quot;using PostgreSQL 16&quot;, &quot;deploying to Vercel&quot;</td></tr><tr><td><code>architecture</code></td><td>Fatti strutturali sul codebase</td><td>&quot;React + Ink for TUI&quot;, &quot;tsup for bundling&quot;</td></tr><tr><td><code>facts</code></td><td>Contesto generale (default)</td><td>&quot;Node 22 is installed&quot;, &quot;kDrive slows file I/O&quot;</td></tr></tbody></table><h2 id="il-tool-save-memory" tabindex="-1">Il Tool <code>save_memory</code> <a class="header-anchor" href="#il-tool-save-memory" aria-label="Permalink to &quot;Il Tool \`save_memory\`&quot;">​</a></h2><p>L&#39;LLM ha un tool <code>save_memory</code> che chiama quando impara qualcosa di duraturo:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>tool: save_memory({&quot;content&quot;: &quot;User prefers pnpm, never npm&quot;, &quot;category&quot;: &quot;preferences&quot;})</span></span></code></pre></div><p><strong>Cosa salva l&#39;LLM</strong>: preferenze, decisioni, fatti di architettura, contesto del progetto — cose utili in <em>sessioni future</em>.</p><p><strong>Cosa NON salva l&#39;LLM</strong>: stato transitorio (&quot;attualmente sto editando il file X&quot;), fatti ovvi, cose già in <code>AGENTS.md</code>.</p><p>Il tool è sempre attivo e non può essere disabilitato per agente. Scrive solo in <code>.turbodev/memory.md</code> (gitignored) — non può modificare altri file.</p><h2 id="comandi" tabindex="-1">Comandi <a class="header-anchor" href="#comandi" aria-label="Permalink to &quot;Comandi&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Comando</th><th>Descrizione</th></tr></thead><tbody><tr><td><code>/memory</code></td><td>Mostra tutte le entry di memoria raggruppate per categoria</td></tr><tr><td><code>/memory show</code></td><td>Come <code>/memory</code></td></tr><tr><td><code>/memory add &lt;text&gt;</code></td><td>Aggiunge una entry a <code>facts</code> (categoria default)</td></tr><tr><td><code>/memory add &lt;category&gt; &lt;text&gt;</code></td><td>Aggiunge una entry a una categoria specifica</td></tr><tr><td><code>/memory clear</code></td><td>Cancella tutta la memoria (chiede conferma)</td></tr><tr><td><code>/memory clear &lt;category&gt;</code></td><td>Cancella una categoria (chiede conferma)</td></tr><tr><td><code>/memory reload</code></td><td>Rilegge <code>.turbodev/memory.md</code> da disco</td></tr></tbody></table><h3 id="esempi" tabindex="-1">Esempi <a class="header-anchor" href="#esempi" aria-label="Permalink to &quot;Esempi&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/memory add preferences Use 2-space indentation, never tabs</span></span>
<span class="line"><span>/memory add decisions We deploy to Vercel, not Netlify</span></span>
<span class="line"><span>/memory add The project uses Tailwind CSS v4</span></span>
<span class="line"><span>/memory clear decisions</span></span></code></pre></div><h2 id="modifica-manuale" tabindex="-1">Modifica Manuale <a class="header-anchor" href="#modifica-manuale" aria-label="Permalink to &quot;Modifica Manuale&quot;">​</a></h2><p>Il file di memoria è Markdown plain — aprilo in qualsiasi editor:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Nel tuo editor</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">vim</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .turbodev/memory.md</span></span></code></pre></div><p>Dopo aver salvato, esegui <code>/memory reload</code> in TurboDev per picks up le modifiche.</p><h2 id="budget-di-token" tabindex="-1">Budget di Token <a class="header-anchor" href="#budget-di-token" aria-label="Permalink to &quot;Budget di Token&quot;">​</a></h2><p>La memoria viene iniettata nel system prompt, il che consuma token della context window. TurboDev mostra un warning quando la memoria supera ~500 token (circa 2KB di Markdown).</p><p>Per ridurre l&#39;uso di memoria:</p><ul><li><code>/memory clear &lt;category&gt;</code> per rimuovere entry obsolete</li><li>Modifica <code>.turbodev/memory.md</code> manualmente e <code>/memory reload</code></li><li><code>/memory clear</code> per cancellare tutto e ripartire da zero</li></ul><h2 id="sicurezza-della-compattazione" tabindex="-1">Sicurezza della Compattazione <a class="header-anchor" href="#sicurezza-della-compattazione" aria-label="Permalink to &quot;Sicurezza della Compattazione&quot;">​</a></h2><p>Quando una conversazione viene compattata (<code>/compact</code> o auto-compattazione all&#39;85%), la cronologia della conversazione viene riassunta ma il <strong>system prompt viene preservato</strong>. Poiché la memoria vive nel system prompt, i tuoi fatti persistenti sopravvivono alla compattazione — non vengono mai persi o riassunti.</p><h2 id="agents-md-vs-memoria" tabindex="-1">AGENTS.md vs Memoria <a class="header-anchor" href="#agents-md-vs-memoria" aria-label="Permalink to &quot;AGENTS.md vs Memoria&quot;">​</a></h2><table tabindex="0"><thead><tr><th></th><th>AGENTS.md</th><th>Memoria (.turbodev/memory.md)</th></tr></thead><tbody><tr><td><strong>Scritto da</strong></td><td>Utente (manuale)</td><td>LLM (via <code>save_memory</code>) + Utente</td></tr><tr><td><strong>Committato in git</strong></td><td>Sì (condiviso col team)</td><td>No (gitignored, personale)</td></tr><tr><td><strong>Contenuto</strong></td><td>Spec del progetto, setup, convenzioni</td><td>Fatti appresi, preferenze, decisioni</td></tr><tr><td><strong>Scope</strong></td><td>Statico, autorevole</td><td>Dinamico, supplementare</td></tr></tbody></table><p>Entrambi coesistono nel system prompt. AGENTS.md è la spec autorevole del progetto; la memoria è contesto supplementare che l&#39;AI ha appreso.</p><h2 id="limitazioni-v1" tabindex="-1">Limitazioni (V1) <a class="header-anchor" href="#limitazioni-v1" aria-label="Permalink to &quot;Limitazioni (V1)&quot;">​</a></h2><ul><li><strong>Solo a livello progetto</strong> — niente memoria globale cross-project (V2)</li><li><strong>Niente deduplication</strong> — se l&#39;LLM salva lo stesso fatto due volte, pulisci manualmente</li><li><strong>Niente auto-capture dalla compattazione</strong> — solo il tool <code>save_memory</code> e <code>/memory add</code></li><li><strong>Soft cap ~500 token</strong> — niente truncation automatica, solo warning nell&#39;UI</li><li><strong>Niente memoria per-agente</strong> — tutti gli agenti in un progetto condividono lo stesso file</li></ul>`,36)])])}const u=t(n,[["render",s]]);export{h as __pageData,u as default};
